from dataclasses import dataclass, field
from datetime import date
from typing import Literal

Status = Literal["ok", "warning", "breach", "unknown"]

@dataclass
class ContractObligation:
    obligation_id: str          # e.g. "openai-2024-seat-limit"
    vendor: str
    dimension: str              # usage | data | access | sla
    description: str
    measurement_query: str      # SQL / API call that returns current value
    limit: float | None         # None if qualitative (e.g. DPA signed = bool)
    warning_threshold: float    # fraction of limit, e.g. 0.85
    measurement_date: date | None = None
    current_value: float | None = None
    status: Status = "unknown"

    def evaluate(self) -> "ContractObligation":
        if self.current_value is None or self.limit is None:
            self.status = "unknown"
        elif self.current_value >= self.limit:
            self.status = "breach"
        elif self.current_value >= self.limit * self.warning_threshold:
            self.status = "warning"
        else:
            self.status = "ok"
        return self

@dataclass
class ComplianceReport:
    report_date: date
    obligations: list[ContractObligation] = field(default_factory=list)

    @property
    def breach_count(self) -> int:
        return sum(1 for o in self.obligations if o.status == "breach")

    @property
    def warning_count(self) -> int:
        return sum(1 for o in self.obligations if o.status == "warning")

    def summary(self) -> str:
        total = len(self.obligations)
        return (
            f"{self.report_date}: {total} obligations — "
            f"{self.breach_count} breach, {self.warning_count} warning, "
            f"{total - self.breach_count - self.warning_count} ok"
        )

import httpx, os
from datetime import date, timedelta

def fetch_openai_usage(start: date, end: date) -> dict:
    """Fetch daily token usage from OpenAI usage endpoint."""
    token = os.environ["OPENAI_ADMIN_KEY"]
    url = "https://api.openai.com/v1/organization/usage/completions"
    params = {
        "start_time": int(start.strftime("%s")),
        "end_time": int(end.strftime("%s")),
        "bucket_width": "1d",
        "group_by": ["model"],
        "limit": 180,
    }
    r = httpx.get(url, headers={"Authorization": f"Bearer {token}"}, params=params)
    r.raise_for_status()
    return r.json()

def aggregate_tokens(usage_response: dict) -> dict[str, int]:
    """Return {model: total_tokens} from a usage API response."""
    totals: dict[str, int] = {}
    for bucket in usage_response.get("data", []):
        for result in bucket.get("results", []):
            model = result.get("model_id", "unknown")
            tokens = result.get("input_tokens", 0) + result.get("output_tokens", 0)
            totals[model] = totals.get(model, 0) + tokens
    return totals

from dataclasses import dataclass

@dataclass
class SeatReconciliationResult:
    vendor: str
    licensed_seats: int
    provisioned_seats: int
    active_last_30d: int
    orphaned_accounts: list[str]   # emails in vendor but not in IdP

    @property
    def utilisation_pct(self) -> float:
        return self.provisioned_seats / self.licensed_seats * 100

    def compliance_status(self) -> str:
        if self.provisioned_seats > self.licensed_seats:
            return "BREACH: over-provisioned"
        if self.orphaned_accounts:
            return f"WARNING: {len(self.orphaned_accounts)} orphaned accounts"
        return "OK"

def reconcile_seats(
    vendor_users: list[str],
    idp_active_users: set[str],
    licensed_seats: int,
) -> SeatReconciliationResult:
    orphaned = [u for u in vendor_users if u not in idp_active_users]
    return SeatReconciliationResult(
        vendor="vendor",
        licensed_seats=licensed_seats,
        provisioned_seats=len(vendor_users),
        active_last_30d=len([u for u in vendor_users if u in idp_active_users]),
        orphaned_accounts=orphaned,
    )

from dataclasses import dataclass
from datetime import datetime, timedelta
from decimal import Decimal

@dataclass
class SLAIncident:
    incident_id: str
    vendor: str
    start_time: datetime
    end_time: datetime
    impact: str          # "full_outage" | "degraded" | "partial"
    claim_deadline: datetime
    claim_submitted: bool = False
    credit_amount: Decimal | None = None
    credit_applied: bool = False

    @property
    def downtime_minutes(self) -> float:
        return (self.end_time - self.start_time).total_seconds() / 60

    @property
    def claim_overdue(self) -> bool:
        return not self.claim_submitted and datetime.utcnow() > self.claim_deadline

    def estimated_credit(self, monthly_spend: Decimal, sla_pct: float = 99.9) -> Decimal:
        """Rough credit estimate: 10% of monthly spend per 0.1% SLA point missed."""
        allowed_minutes = (30 * 24 * 60) * (1 - sla_pct / 100)
        excess_minutes = max(0, self.downtime_minutes - allowed_minutes)
        credit_pct = min(Decimal("0.30"), Decimal(str(excess_minutes)) / Decimal("1440") * Decimal("0.10"))
        return (monthly_spend * credit_pct).quantize(Decimal("0.01"))

def pending_claims(incidents: list[SLAIncident]) -> list[SLAIncident]:
    """Return incidents where a credit claim should be filed but hasn't been."""
    return [i for i in incidents if not i.claim_submitted and not i.claim_overdue]

import httpx, os
from dataclasses import dataclass
from enum import Enum

class AlertSeverity(Enum):
    P3 = "p3_inform"
    P2 = "p2_warn"
    P1 = "p1_breach"

@dataclass
class ComplianceAlert:
    obligation_id: str
    severity: AlertSeverity
    message: str
    detail_url: str

def post_slack_alert(alert: ComplianceAlert, webhook_url: str) -> None:
    colour = {"p3_inform": "#3b82f6", "p2_warn": "#f59e0b", "p1_breach": "#ef4444"}[alert.severity.value]
    payload = {
        "attachments": [{
            "color": colour,
            "title": f"[{alert.severity.name}] Compliance alert: {alert.obligation_id}",
            "text": alert.message,
            "actions": [{"type": "button", "text": "View details", "url": alert.detail_url}],
        }]
    }
    httpx.post(webhook_url, json=payload).raise_for_status()

def raise_alerts(report: "ComplianceReport") -> list[ComplianceAlert]:
    alerts = []
    for ob in report.obligations:
        if ob.status == "breach":
            alerts.append(ComplianceAlert(
                ob.obligation_id, AlertSeverity.P1,
                f"BREACH: {ob.description} — current {ob.current_value} vs limit {ob.limit}",
                f"https://compliance.internal/obligations/{ob.obligation_id}",
            ))
        elif ob.status == "warning":
            alerts.append(ComplianceAlert(
                ob.obligation_id, AlertSeverity.P2,
                f"WARNING: {ob.description} at {ob.current_value / ob.limit * 100:.1f}% of limit",
                f"https://compliance.internal/obligations/{ob.obligation_id}",
            ))
    return alerts
